def get_chemical_diversity(inchis):
    """Calculate diversity scores using Morgan fingerprints and Tanimoto similarity."""
    fingerprints = []
    valid_inchis = []
    for inchi in inchis:
        mol = Chem.MolFromInchi(inchi)
        if mol:
            fp = AllChem.GetMorganFingerprintAsBitVect(mol, radius=2, nBits=2048)
            fingerprints.append(fp)
            valid_inchis.append(inchi)

