def get_assay_name(aid: int):
    """ uses PubChem PUGRest to revieve Bioassay name """
    url = "https://pubchem.ncbi.nlm.nih.gov/rest/pug/assay/aid/{}/description/json".format(aid)
    r = requests.get(url)
    if r.status_code == 200:
        json_data = r.json()
        name = json_data["PC_AssayContainer"][0]['assay']['descr']['name']
        return name, None
    else:
        return r.status_code, r.reason

def import_pubchem_aid(aid: int):
    raw_data, error = get_raw_bioactivity_data(aid)
    if error:
        return None, error
    bioactivity, clean_error = clean_bioactivity_frame(raw_data, aid)
    if clean_error:
        return None, clean_error
    cids = bioactivity['CID'].dropna().astype(int).tolist()
    if not cids:
        return None, "No CIDs available to fetch InChI data."

