def select_diverse_compounds(df, num_actives=500, num_inactives=500):
    """Select diverse compounds maintaining a 1:1 ratio of active to inactive compounds."""
    active_df = df[df['activity'] == 1].copy()
    inactive_df = df[df['activity'] == 0].copy()
    if len(df) <= 1000:
        return df  # Return everything if ≤ 1000
    # Compute diversity scores
    if len(active_df) > num_actives:
        diversity_scores_active = get_chemical_diversity(active_df['inchi'].tolist())
        active_df['diversity_score'] = active_df['inchi'].map(diversity_scores_active)

